import React, { useState } from 'react';

const CSPBrandV2 = () => {
  const [activeSlogan, setActiveSlogan] = useState(0);

  // 심플한 2컬러 시스템
  const colors = {
    primary: '#7c3aed',      // Vibe Purple - 메인 브랜드 컬러
    dark: '#1a2332',         // Deep Navy - 텍스트/배경
    light: '#ffffff',        // White
    gray: '#6b7280'          // Gray - 보조 텍스트
  };

  // 임팩트 있는 슬로건 옵션들
  const slogans = [
    {
      ko: "HR을 코딩하다",
      en: "Coding Human Resources",
      tagline: "17년 경험을 코드로 바꾸는 사람"
    },
    {
      ko: "사람을 이해하는 개발자",
      en: "Developer Who Understands People",
      tagline: "HR 전문성 × 풀스택 역량"
    },
    {
      ko: "자동화로 HR 혁신",
      en: "Automate. Transform. Innovate.",
      tagline: "반복을 혁신으로 바꾸다"
    },
    {
      ko: "경험을 시스템으로",
      en: "From Experience to System",
      tagline: "17년 HR 노하우의 자동화"
    }
  ];

  // 심플한 로고 옵션들
  const SimpleLogo1 = ({ size = 120 }) => (
    <svg width={size} height={size} viewBox="0 0 200 200">
      {/* C 모양을 기하학적으로 단순화 */}
      <circle cx="100" cy="100" r="80" fill="none" stroke={colors.primary} strokeWidth="20"/>
      <rect x="100" y="20" width="80" height="160" fill={colors.dark}/>
      <text x="100" y="120" fontSize="60" fontWeight="700" fill={colors.primary} textAnchor="middle" fontFamily="Inter">
        C
      </text>
    </svg>
  );

  const SimpleLogo2 = ({ size = 120 }) => (
    <svg width={size} height={size} viewBox="0 0 200 200">
      {/* 코드 브라켓 + 사람 */}
      <path d="M 60 50 L 40 100 L 60 150" stroke={colors.primary} strokeWidth="16" fill="none" strokeLinecap="round"/>
      <path d="M 140 50 L 160 100 L 140 150" stroke={colors.primary} strokeWidth="16" fill="none" strokeLinecap="round"/>
      <circle cx="100" cy="80" r="20" fill={colors.primary}/>
      <path d="M 100 100 L 100 140 M 80 120 L 100 100 L 120 120 M 100 140 L 80 160 M 100 140 L 120 160" 
            stroke={colors.primary} strokeWidth="12" fill="none" strokeLinecap="round"/>
    </svg>
  );

  const SimpleLogo3 = ({ size = 120 }) => (
    <svg width={size} height={size} viewBox="0 0 200 200">
      {/* 심플한 C + 그라디언트 */}
      <defs>
        <linearGradient id="grad1" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" style={{stopColor: colors.primary, stopOpacity: 1}} />
          <stop offset="100%" style={{stopColor: colors.dark, stopOpacity: 1}} />
        </linearGradient>
      </defs>
      <path d="M 160 100 A 60 60 0 1 0 160 100 Z" fill="url(#grad1)"/>
      <circle cx="100" cy="100" r="40" fill={colors.dark}/>
      <text x="100" y="118" fontSize="48" fontWeight="700" fill="white" textAnchor="middle" fontFamily="Inter">
        C
      </text>
