import React, { useState } from 'react';

const CSPBrandDark = () => {
  const [selectedLogo, setSelectedLogo] = useState(0);
  const [selectedSlogan, setSelectedSlogan] = useState(0);

  // 다크 그레이 컬러 시스템
  const colors = {
    black: '#0a0a0a',           // 최고 다크
    dark: '#1a1a1a',            // 메인 배경
    darkGray: '#2d2d2d',        // 카드 배경
    mediumGray: '#404040',      // 구분선
    lightGray: '#a3a3a3',       // 보조 텍스트
    white: '#fafafa',           // 메인 텍스트
    accent: '#7c3aed',          // 포인트 컬러 (극히 절제)
  };

  // 슬로건
  const slogans = [
    { text: 'HR × CODE', sub: '17년 경험을 시스템으로' },
    { text: 'AUTOMATE HR', sub: '반복을 혁신으로' },
    { text: 'CODE THE HUMAN', sub: '사람을 코딩하다' },
  ];

  // 볼드 로고 옵션들
  const BoldLogo1 = ({ size = 120, mono = false }) => (
    <svg width={size} height={size} viewBox="0 0 200 200">
      {/* 사각형 프레임 + C */}
      <rect x="20" y="20" width="160" height="160" fill="none" 
            stroke={mono ? colors.white : colors.accent} strokeWidth="8"/>
      <text x="100" y="130" fontSize="100" fontWeight="900" 
            fill={mono ? colors.white : colors.accent} 
            textAnchor="middle" fontFamily="Inter">C</text>
    </svg>
  );

  const BoldLogo2 = ({ size = 120, mono = false }) => (
    <svg width={size} height={size} viewBox="0 0 200 200">
      {/* 강렬한 C - 두꺼운 획 */}
      <path d="M 150 60 A 60 60 0 1 0 150 140" 
            stroke={mono ? colors.white : colors.accent} 
            strokeWidth="30" fill="none" strokeLinecap="square"/>
    </svg>
  );

  const BoldLogo3 = ({ size = 120, mono = false }) => (
    <svg width={size} height={size} viewBox="0 0 200 200">
      {/* 블록 C */}
      <path d="M 160 40 L 60 40 C 40 40 40 60 40 80 L 40 120 C 40 140 40 160 60 160 L 160 160 L 160 130 L 80 130 L 80 70 L 160 70 Z" 
            fill={mono ? colors.white : colors.accent}/>
    </svg>
  );

  const logos = [
    { Component: BoldLogo1, name: 'FRAME C', desc: '프레임 속의 강렬함' },
    { Component: BoldLogo2, name: 'BOLD C', desc: '두꺼운 획의 힘' },
    { Component: BoldLogo3, name: 'BLOCK C', desc: '블록 타이포그래피' },
  ];

