    <div style={{ 
      minHeight: '100vh', 
      background: colors.dark,
      color: colors.white,
      fontFamily: 'Inter, sans-serif',
    }}>
      {/* Hero */}
      <div style={{
        background: colors.black,
        padding: '4rem 2rem',
        borderBottom: `2px solid ${colors.mediumGray}`
      }}>
        <div style={{ maxWidth: '1400px', margin: '0 auto', textAlign: 'center' }}>
          {logos[selectedLogo].Component({ size: 160, mono: true })}

          <h1 style={{ 
            fontSize: '5rem', 
            fontWeight: '900', 
            margin: '2rem 0 0.5rem',
            letterSpacing: '-0.05em',
            textTransform: 'uppercase'
          }}>
            CSP
          </h1>

          <div style={{ 
            fontSize: '2.5rem', 
            fontWeight: '800',
            marginBottom: '1rem',
            letterSpacing: '0.1em',
            color: colors.lightGray
          }}>
            {slogans[selectedSlogan].text}
          </div>

          <div style={{ 
            fontSize: '1.25rem',
            color: colors.lightGray,
            fontWeight: '400'
          }}>
            {slogans[selectedSlogan].sub}
          </div>
        </div>
      </div>

      <div style={{ maxWidth: '1400px', margin: '0 auto', padding: '3rem 2rem' }}>
