                  transition: 'all 0.3s',
                  textAlign: 'center'
                }}
                onMouseEnter={(e) => {
                  if (selectedLogo !== idx) {
                    e.currentTarget.style.borderColor = colors.mediumGray;
                    e.currentTarget.style.transform = 'translateY(-4px)';
                  }
                }}
                onMouseLeave={(e) => {
                  if (selectedLogo !== idx) {
                    e.currentTarget.style.borderColor = colors.mediumGray;
                    e.currentTarget.style.transform = 'translateY(0)';
                  }
                }}
              >
                <logo.Component size={140} />
                <div style={{ 
                  marginTop: '1.5rem', 
                  fontSize: '1.25rem',
                  fontWeight: '700',
                  letterSpacing: '0.05em'
                }}>
                  {logo.name}
                </div>
                <div style={{ 
                  fontSize: '0.875rem',
                  color: colors.lightGray,
                  marginTop: '0.5rem'
                }}>
                  {logo.desc}
                </div>
