                <div style={{ fontWeight: '700', fontSize: '1.125rem', marginBottom: '0.5rem' }}>BLACK</div>
                <div style={{ fontFamily: 'monospace', fontSize: '0.875rem', color: colors.lightGray }}>
                  #0a0a0a
                </div>
                <div style={{ fontSize: '0.75rem', color: colors.lightGray, marginTop: '0.5rem' }}>
                  배경, 강조 영역
                </div>
              </div>

              <div>
                <div style={{ 
                  width: '100%', 
