                  </div>
                  <div style={{ fontSize: '0.875rem', color: colors.lightGray, marginBottom: '0.5rem' }}>
                    {slogans[selectedSlogan].sub}
                  </div>
                  <div style={{ fontSize: '0.75rem', color: colors.lightGray }}>
                    your.email@example.com | LG PRI
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>
      </div>

      {/* Footer CTA */}
      <div style={{
        background: colors.black,
        padding: '4rem 2rem',
        marginTop: '4rem',
        borderTop: `2px solid ${colors.mediumGray}`,
        textAlign: 'center'
      }}>
        <div style={{ maxWidth: '800px', margin: '0 auto' }}>
          <div style={{ fontSize: '2.5rem', fontWeight: '900', marginBottom: '1rem', letterSpacing: '-0.02em' }}>
            선택 완료
          </div>
          <div style={{ fontSize: '1.125rem', color: colors.lightGray, marginBottom: '2rem' }}>
            선택한 로고: {logos[selectedLogo].name} | 슬로건: {slogans[selectedSlogan].text}
          </div>
          <button style={{
            background: colors.accent,
            color: 'white',
            padding: '1.25rem 3rem',
            fontSize: '1.125rem',
            fontWeight: '700',
            border: 'none',
            cursor: 'pointer',
            textTransform: 'uppercase',
            letterSpacing: '0.05em',
            transition: 'all 0.3s'
          }}
          onMouseEnter={(e) => {
            e.target.style.background = '#6d28d9';
          }}
          onMouseLeave={(e) => {
            e.target.style.background = colors.accent;
          }}>
            DOWNLOAD BRAND KIT
          </button>
