import React, { useState, useEffect } from 'react';

const CSPBrandPro = () => {
  const [selectedLogo, setSelectedLogo] = useState(0);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovering, setIsHovering] = useState(false);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePos({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // 프로페셔널 다크 컬러 시스템
  const colors = {
    void: '#0d0d0d',
    obsidian: '#1a1a1a',
    slate: '#2a2a2a',
    steel: '#3d3d3d',
    concrete: '#707070',
    platinum: '#e8e8e8',
    // 절제된 액센트 - 차가운 청록색 (보라 대신)
    accent: '#00d9ff',
  };

  const slogans = [
    { main: 'HR/CODE', sub: 'SYSTEMIC TRANSFORMATION' },
    { main: 'CODE:HUMAN', sub: 'ENGINEERING EXPERIENCE' },
    { main: '17Y → ∞', sub: 'INFINITE AUTOMATION' },
  ];

  // 기하학적 로고들
  const GeometricLogo = ({ size = 120, variant = 0 }) => {
    const designs = [
      // 1. 브루탈리스트 사각형
      <svg width={size} height={size} viewBox="0 0 200 200">
        <defs>
          <filter id="noise">
            <feTurbulence type="fractalNoise" baseFrequency="0.9" numOctaves="4" />
            <feColorMatrix type="saturate" values="0"/>
            <feComponentTransfer>
              <feFuncA type="discrete" tableValues="0 1"/>
            </feComponentTransfer>
          </filter>
        </defs>
        <rect x="30" y="30" width="140" height="140" fill={colors.platinum} />
        <rect x="35" y="35" width="130" height="130" fill={colors.obsidian} />
        <path d="M 70 90 L 70 110 L 50 110 L 50 70 L 130 70 L 130 90 Z M 130 130 L 130 110 L 150 110 L 150 150 L 70 150 L 70 130 Z" 
              fill={colors.platinum} />
        <rect x="0" y="0" width="200" height="200" fill="url(#noise)" opacity="0.03"/>
      </svg>,

      // 2. 디지털 그리드
      <svg width={size} height={size} viewBox="0 0 200 200">
        <defs>
          <pattern id="grid" x="0" y="0" width="20" height="20" patternUnits="userSpaceOnUse">
            <path d="M 20 0 L 0 0 0 20" fill="none" stroke={colors.steel} strokeWidth="0.5"/>
          </pattern>
        </defs>
        <rect width="200" height="200" fill="url(#grid)"/>
        <rect x="40" y="40" width="120" height="120" fill={colors.obsidian} stroke={colors.accent} strokeWidth="3"/>
        <text x="100" y="125" fontSize="70" fontWeight="900" fill={colors.platinum} 
              textAnchor="middle" fontFamily="'Space Mono', monospace" letterSpacing="-5">C</text>
        <line x1="60" y1="60" x2="140" y2="60" stroke={colors.accent} strokeWidth="2"/>
        <line x1="60" y1="140" x2="140" y2="140" stroke={colors.accent} strokeWidth="2"/>
      </svg>,

      // 3. 타이포그래피 몬스터
      <svg width={size} height={size} viewBox="0 0 200 200">
        <text x="100" y="140" fontSize="180" fontWeight="900" fill={colors.platinum} 
              textAnchor="middle" fontFamily="'Bebas Neue', 'Oswald', sans-serif" 
              letterSpacing="-10">C</text>
        <rect x="85" y="50" width="30" height="3" fill={colors.accent}/>
        <rect x="85" y="145" width="30" height="3" fill={colors.accent}/>
      </svg>,
    ];
    return designs[variant];
  };

  return (
    <div style={{ 
      minHeight: '100vh',
      background: colors.obsidian,
      color: colors.platinum,
      fontFamily: "'Space Mono', 'Courier New', monospace",
      position: 'relative',
      overflow: 'hidden'
    }}>
      {/* 커스텀 커서 효과 */}
      <div style={{
        position: 'fixed',
        left: mousePos.x - 20,
        top: mousePos.y - 20,
        width: '40px',
        height: '40px',
        border: `2px solid ${colors.accent}`,
        borderRadius: '50%',
        pointerEvents: 'none',
        zIndex: 9999,
        transition: 'width 0.2s, height 0.2s',
        opacity: 0.5,
        ...(isHovering && {
          width: '60px',
          height: '60px',
          left: mousePos.x - 30,
          top: mousePos.y - 30,
        })
      }}/>

      {/* 배경 노이즈 그리드 */}
      <div style={{
        position: 'fixed',
        inset: 0,
        backgroundImage: `
          repeating-linear-gradient(0deg, transparent, transparent 2px, ${colors.slate} 2px, ${colors.slate} 4px),
          repeating-linear-gradient(90deg, transparent, transparent 2px, ${colors.slate} 2px, ${colors.slate} 4px)
        `,
        opacity: 0.15,
        pointerEvents: 'none'
      }}/>

      {/* Hero Section */}
      <div style={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        position: 'relative',
        padding: '2rem'
      }}>
        <div style={{
          maxWidth: '1400px',
          width: '100%',
          position: 'relative'
        }}>
          {/* 배경 대형 C */}
          <div style={{
            position: 'absolute',
            fontSize: '60rem',
            fontWeight: '900',
            color: colors.void,
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            opacity: 0.3,
            fontFamily: "'Bebas Neue', sans-serif",
            letterSpacing: '-2rem',
            userSelect: 'none',
            zIndex: 0
          }}>
            C
          </div>

          <div style={{ position: 'relative', zIndex: 1 }}>
            {/* 로고 */}
            <div style={{
              marginBottom: '4rem',
              animation: 'fadeSlideDown 1s ease-out'
            }}>
              <GeometricLogo size={200} variant={selectedLogo} />
            </div>

            {/* 메인 타이틀 */}
            <div style={{
              display: 'flex',
              flexDirection: 'column',
              gap: '1rem',
              animation: 'fadeSlideUp 1s ease-out 0.2s both'
            }}>
              <div style={{
                fontSize: '8rem',
                fontWeight: '900',
                fontFamily: "'Bebas Neue', 'Oswald', sans-serif",
                letterSpacing: '-0.05em',
                lineHeight: '0.9',
                textTransform: 'uppercase'
              }}>
                CSP
              </div>

              <div style={{
                fontSize: '3rem',
                fontWeight: '700',
                fontFamily: "'Space Mono', monospace",
                letterSpacing: '0.2em',
                color: colors.concrete,
                position: 'relative',
                paddingLeft: '1rem'
              }}>
                <div style={{
                  position: 'absolute',
                  left: 0,
                  top: '50%',
                  transform: 'translateY(-50%)',
                  width: '4px',
                  height: '100%',
                  background: colors.accent,
                  animation: 'expandHeight 0.5s ease-out 0.5s both'
                }}/>
                {slogans[0].main}
              </div>

              <div style={{
                fontSize: '1.25rem',
                fontFamily: "'Space Mono', monospace",
                letterSpacing: '0.15em',
                color: colors.concrete,
                textTransform: 'uppercase',
                opacity: 0.7
              }}>
                {slogans[0].sub}
              </div>
            </div>

            {/* 스크롤 인디케이터 */}
            <div style={{
              marginTop: '6rem',
              display: 'flex',
              alignItems: 'center',
              gap: '1rem',
              color: colors.concrete,
              fontSize: '0.75rem',
              letterSpacing: '0.2em',
              animation: 'fadeIn 1s ease-out 1s both'
            }}>
              <div style={{
                width: '1px',
                height: '40px',
                background: colors.accent,
                animation: 'scrollLine 2s ease-in-out infinite'
              }}/>
              <span>SCROLL TO EXPLORE</span>
            </div>
          </div>
        </div>
      </div>

      {/* Logo Variants Section */}
      <div style={{
        minHeight: '100vh',
        padding: '8rem 2rem',
        background: colors.void
      }}>
        <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
          <h2 style={{
            fontSize: '4rem',
            fontWeight: '900',
            fontFamily: "'Bebas Neue', sans-serif",
            letterSpacing: '0.05em',
            marginBottom: '4rem',
            position: 'relative',
            paddingBottom: '1rem'
          }}>
            LOGO SYSTEM
            <div style={{
              position: 'absolute',
              bottom: 0,
              left: 0,
              width: '200px',
              height: '4px',
              background: colors.accent
            }}/>
          </h2>

          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))',
            gap: '3rem'
          }}>
            {[
              { name: 'BRUTALIST SQUARE', desc: 'Architectural. Raw. Uncompromising.' },
              { name: 'DIGITAL GRID', desc: 'Technical. Precise. Systematic.' },
              { name: 'TYPE MONSTER', desc: 'Bold. Dominant. Unforgettable.' }
            ].map((logo, idx) => (
              <div
                key={idx}
                onClick={() => setSelectedLogo(idx)}
                onMouseEnter={() => setIsHovering(true)}
                onMouseLeave={() => setIsHovering(false)}
                style={{
                  background: selectedLogo === idx ? colors.slate : colors.obsidian,
                  border: `2px solid ${selectedLogo === idx ? colors.accent : colors.steel}`,
                  padding: '3rem',
                  cursor: 'pointer',
                  transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                  position: 'relative',
                  overflow: 'hidden',
                  transform: selectedLogo === idx ? 'translateY(-8px)' : 'translateY(0)'
                }}
              >
                {/* 호버 효과 */}
                <div style={{
                  position: 'absolute',
                  top: 0,
                  left: selectedLogo === idx ? 0 : '-100%',
                  width: '4px',
                  height: '100%',
                  background: colors.accent,
                  transition: 'left 0.3s ease'
                }}/>

                <div style={{ marginBottom: '2rem' }}>
                  <GeometricLogo size={180} variant={idx} />
                </div>

                <div style={{
                  fontFamily: "'Space Mono', monospace",
                  fontSize: '1.25rem',
                  fontWeight: '700',
                  letterSpacing: '0.1em',
                  marginBottom: '0.5rem'
                }}>
                  {logo.name}
                </div>

                <div style={{
                  fontFamily: "'Space Mono', monospace",
                  fontSize: '0.875rem',
                  color: colors.concrete,
                  lineHeight: '1.6'
                }}>
                  {logo.desc}
                </div>

                {selectedLogo === idx && (
                  <div style={{
                    marginTop: '1.5rem',
                    padding: '0.75rem 1.5rem',
                    background: colors.accent,
                    color: colors.obsidian,
                    fontWeight: '700',
                    fontSize: '0.875rem',
                    letterSpacing: '0.1em',
                    textAlign: 'center'
                  }}>
                    SELECTED
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Color System */}
      <div style={{
        minHeight: '100vh',
        padding: '8rem 2rem',
        background: colors.obsidian
      }}>
        <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
          <h2 style={{
            fontSize: '4rem',
            fontWeight: '900',
            fontFamily: "'Bebas Neue', sans-serif",
            letterSpacing: '0.05em',
            marginBottom: '4rem'
          }}>
            COLOR SYSTEM
          </h2>

          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
            gap: '0'
          }}>
            {[
              { name: 'VOID', hex: '#0d0d0d', color: colors.void },
              { name: 'OBSIDIAN', hex: '#1a1a1a', color: colors.obsidian },
              { name: 'SLATE', hex: '#2a2a2a', color: colors.slate },
              { name: 'STEEL', hex: '#3d3d3d', color: colors.steel },
              { name: 'CONCRETE', hex: '#707070', color: colors.concrete },
              { name: 'PLATINUM', hex: '#e8e8e8', color: colors.platinum },
            ].map((color, idx) => (
              <div key={idx} style={{
                background: color.color,
                padding: '4rem 2rem',
                borderRight: idx < 5 ? `1px solid ${colors.steel}` : 'none',
                transition: 'all 0.3s',
                cursor: 'pointer'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'scale(1.05)';
                e.currentTarget.style.zIndex = '10';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'scale(1)';
                e.currentTarget.style.zIndex = '1';
              }}>
                <div style={{
                  fontFamily: "'Space Mono', monospace",
                  fontSize: '1.5rem',
                  fontWeight: '700',
                  letterSpacing: '0.1em',
                  marginBottom: '1rem',
                  color: idx < 3 ? colors.platinum : colors.obsidian
                }}>
                  {color.name}
                </div>
                <div style={{
                  fontFamily: "'Space Mono', monospace",
                  fontSize: '0.875rem',
                  color: idx < 3 ? colors.concrete : colors.steel,
                  letterSpacing: '0.05em'
                }}>
                  {color.hex}
                </div>
              </div>
            ))}
          </div>

          {/* Accent */}
          <div style={{
            marginTop: '3rem',
            background: colors.void,
            border: `3px solid ${colors.accent}`,
            padding: '3rem',
            position: 'relative',
            overflow: 'hidden'
          }}>
            <div style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '100%',
              height: '4px',
              background: colors.accent,
              animation: 'slideRight 2s ease-in-out infinite'
            }}/>

            <div style={{
              fontFamily: "'Space Mono', monospace",
              fontSize: '2rem',
              fontWeight: '700',
              letterSpacing: '0.1em',
              marginBottom: '1rem',
              color: colors.accent
            }}>
              ACCENT / CYAN
            </div>
            <div style={{
              fontFamily: "'Space Mono', monospace",
              fontSize: '1.125rem',
              color: colors.concrete
            }}>
              #00d9ff — USE SPARINGLY. Maximum 5% of design.
            </div>
          </div>
        </div>
      </div>

      {/* Business Card Preview */}
      <div style={{
        minHeight: '100vh',
        padding: '8rem 2rem',
        background: colors.void,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}>
        <div style={{ maxWidth: '1400px', width: '100%' }}>
          <h2 style={{
            fontSize: '4rem',
            fontWeight: '900',
            fontFamily: "'Bebas Neue', sans-serif",
            letterSpacing: '0.05em',
            marginBottom: '4rem',
            textAlign: 'center'
          }}>
            BUSINESS CARD
          </h2>

          <div style={{
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: '4rem',
            maxWidth: '1200px',
            margin: '0 auto'
          }}>
            {/* Front */}
            <div style={{
              aspectRatio: '1.586/1',
              background: colors.obsidian,
              border: `2px solid ${colors.steel}`,
              padding: '4rem 3rem',
              position: 'relative',
              overflow: 'hidden'
            }}>
              <div style={{
                position: 'absolute',
                top: 0,
                right: 0,
                width: '50%',
                height: '100%',
                background: `linear-gradient(135deg, transparent 0%, ${colors.void} 100%)`,
                opacity: 0.5
              }}/>

              <div style={{ position: 'relative', zIndex: 1, height: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
                <GeometricLogo size={80} variant={selectedLogo} />

                <div>
                  <div style={{
                    fontFamily: "'Bebas Neue', sans-serif",
                    fontSize: '4rem',
                    fontWeight: '900',
                    letterSpacing: '-0.02em',
                    marginBottom: '0.5rem'
                  }}>
                    CSP
                  </div>
                  <div style={{
                    fontFamily: "'Space Mono', monospace",
                    fontSize: '1.125rem',
                    fontWeight: '700',
                    letterSpacing: '0.2em',
                    color: colors.concrete
                  }}>
                    HR/CODE
                  </div>
                </div>
              </div>
            </div>

            {/* Back */}
            <div style={{
              aspectRatio: '1.586/1',
              background: colors.slate,
              border: `2px solid ${colors.accent}`,
              borderLeft: `8px solid ${colors.accent}`,
              padding: '4rem 3rem',
              position: 'relative'
            }}>
              <div style={{ height: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
                <div>
                  <div style={{
                    fontFamily: "'Space Mono', monospace",
                    fontSize: '1.75rem',
                    fontWeight: '700',
                    marginBottom: '0.5rem'
                  }}>
                    [YOUR NAME]
                  </div>
                  <div style={{
                    fontFamily: "'Space Mono', monospace",
                    fontSize: '0.875rem',
                    color: colors.concrete,
                    textTransform: 'uppercase',
                    letterSpacing: '0.1em'
                  }}>
                    Creative Solution Provider
                  </div>
                </div>

                <div style={{
                  fontFamily: "'Space Mono', monospace",
                  fontSize: '0.875rem',
                  color: colors.concrete,
                  lineHeight: '2'
                }}>
                  your.email@example.com<br/>
                  linkedin.com/in/profile<br/>
                  LG PRI — 17 YEARS
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Oswald:wght@700;900&family=Space+Mono:wght@400;700&display=swap');

        @keyframes fadeSlideDown {
          from { opacity: 0; transform: translateY(-30px); }
          to { opacity: 1; transform: translateY(0); }
        }

        @keyframes fadeSlideUp {
          from { opacity: 0; transform: translateY(30px); }
          to { opacity: 1; transform: translateY(0); }
        }

        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }

        @keyframes expandHeight {
          from { height: 0%; }
          to { height: 100%; }
        }

        @keyframes scrollLine {
          0%, 100% { transform: scaleY(0.3); opacity: 0.3; }
          50% { transform: scaleY(1); opacity: 1; }
        }

        @keyframes slideRight {
          0% { transform: translateX(-100%); }
          50% { transform: translateX(100%); }
          100% { transform: translateX(100%); }
        }

        * {
          cursor: none;
        }

        a, button {
          cursor: none;
        }
      `}</style>
    </div>
  );
};

export default CSPBrandPro;

